command:
// =========================
// MASTER HEX DETAIL GENERATOR
// Dispatcher Macro
// =========================

function roll(sides) {
    return Math.ceil(Math.random() * sides);
}

function tableRoll(value, table) {
    return table.find(row => value >= row.min && value <= row.max);
}

const featureTable = [
    { min: 1, max: 3, result: "Landmark", macro: "Landmark Generator" },
{ min: 4, max: 4, result: "Settlement", macro: null },
{ min: 5, max: 5, result: "Lair", macro: "Lair Generator" },
{ min: 6, max: 6, result: "Dungeon", macro: "Master Dungeon Generator" }
];

const biomeTable = [
    { min: 1, max: 4, result: "Grassland" },
{ min: 5, max: 6, result: "Forest" },
{ min: 7, max: 8, result: "Hills" },
{ min: 9, max: 9, result: "Marsh" },
{ min: 10, max: 10, result: "Mountains" }
];

const settlementTable = [
    { roll: 1, result: "Hamlet", macro: "Hamlet Generator" },
{ roll: 2, result: "Village", macro: "Village Generator" },
{ roll: 3, result: "City", macro: "City Generator" },
{ roll: 4, result: "Castle", macro: "Castle Generator" },
{ roll: 5, result: "Tower", macro: "Tower Generator" },
{ roll: 6, result: "Abbey", macro: "Abbey Generator" }
];

const options = await Dialog.prompt({
    title: "Master Hex Detail Generator",
    content: `
    <form>
    <p><b>Biome Options</b></p>
    <label>
    <input type="checkbox" id="generateBiome">
    Generate Biome
    </label>

    <p>Existing Biome:</p>
    <select id="biome">
    <option>Grassland</option>
    <option>Forest</option>
    <option>Hills</option>
    <option>Marsh</option>
    <option>Mountains</option>
    </select>

    <hr>

    <p><b>Feature Options</b></p>
    <label>
    <input type="checkbox" id="generateFeature" checked>
    Generate Feature
    </label>

    <p>Existing Feature:</p>
    <select id="feature">
    <option>Landmark</option>
    <option>Settlement</option>
    <option>Lair</option>
    <option>Dungeon</option>
    </select>
    </form>
    `,
    callback: html => ({
        generateBiome: html.find("#generateBiome")[0].checked,
                       biome: html.find("#biome").val(),
                       generateFeature: html.find("#generateFeature")[0].checked,
                       feature: html.find("#feature").val()
    })
});

// -------------------------
// BIOME
// -------------------------

let biomeRoll = null;
let biome = options.biome;

if (options.generateBiome) {
    biomeRoll = roll(10);
    biome = tableRoll(biomeRoll, biomeTable).result;
}

// Store biome globally in case later macros are updated to read it
globalThis.currentHexBiome = biome;

// -------------------------
// FACTION
// -------------------------
async function drawFaction(tableName = "Sandbox Factions") {
    const table = game.tables.getName(tableName);

    if (!table) {
        ui.notifications.warn(`Faction table not found: ${tableName}`);
        return null;
    }

    const draw = await table.draw({ displayChat: false });
    const result = draw.results?.[0]?.text ?? null;

    globalThis.currentHexFaction = result;

    return result;
}

// -------------------------
// FEATURE
// -------------------------

let featureRoll = null;
let feature = options.feature;
let featureMacroName = null;

if (options.generateFeature) {
    featureRoll = roll(6);
    const featureData = tableRoll(featureRoll, featureTable);
    feature = featureData.result;
    featureMacroName = featureData.macro;
} else {
    const featureData = featureTable.find(f => f.result === feature);
    featureMacroName = featureData?.macro ?? null;
}

globalThis.currentHexFeature = feature;

// -------------------------
// OUTPUT HEADER
// -------------------------

let output = `
<h2>Master Hex Detail Generator</h2>

<h3>Hex Setup</h3>

<p><b>Biome:</b> ${biome}</p>
${options.generateBiome ? `<p><b>Biome Roll:</b> d10 = ${biomeRoll}</p>` : `<p><i>Biome was manually selected.</i></p>`}

<hr>

<h3>Feature</h3>

<p><b>Feature:</b> ${feature}</p>
${options.generateFeature ? `<p><b>Feature Roll:</b> d6 = ${featureRoll}</p>` : `<p><i>Feature was manually selected.</i></p>`}
`;

ChatMessage.create({
    speaker: ChatMessage.getSpeaker(),
                   content: output
});

// -------------------------
// DISPATCH
// -------------------------

if (feature === "Settlement") {
    const settlementRoll = roll(6);
    const settlementData = settlementTable.find(s => s.roll === settlementRoll);

    globalThis.currentSettlementType = settlementData.result;

    const factionQualifies = ["City", "Castle", "Tower", "Abbey"].includes(settlementData.result);
    let faction = null;


    if (factionQualifies) {
        faction = await drawFaction("Sandbox Factions");
    }



    await ChatMessage.create({
        speaker: ChatMessage.getSpeaker(),
                             content: `
                             <h3>Settlement Type</h3>
                             <p><b>Settlement Type Roll:</b> d6 = ${settlementRoll}</p>
                             <p><b>Settlement Type:</b> ${settlementData.result}</p>
                             ${faction ? `<p><b>Faction:</b> ${faction}</p>` : `<p><i>No faction assigned.</i></p>`}
                             <p><b>Running Macro:</b> ${settlementData.macro}</p>
                             `
    });

    const macro = game.macros.getName(settlementData.macro);

    if (!macro) {
        ui.notifications.error(`Macro not found: ${settlementData.macro}`);
    } else {
        await macro.execute();
    }

} else {
    const macro = game.macros.getName(featureMacroName);

    if (!macro) {
        ui.notifications.error(`Macro not found: ${featureMacroName}`);
    } else {
        await ChatMessage.create({
            speaker: ChatMessage.getSpeaker(),
                                 content: `
                                 <p><b>Running Macro:</b> ${featureMacroName}</p>
                                 `
        });

        if (feature === "Lair") {
            const faction = await drawFaction("Sandbox Factions");

            await ChatMessage.create({
                speaker: ChatMessage.getSpeaker(),
                                     content: `
                                     <h3>Faction</h3>
                                     <p><b>Qualifying Feature:</b> Lair</p>
                                     ${faction ? `<p><b>Faction:</b> ${faction}</p>` : `<p><i>No faction assigned.</i></p>`}
                                     `
            });
        }

        await macro.execute();
    }
}
